13809 void BoUpSLP::scheduleBlock(BlockScheduling *BS) {
13810   if (!BS->ScheduleStart)
13811     return;
13812 
13813   LLVM_DEBUG(dbgs() << "SLP: schedule block " << BS->BB->getName() << "\n");
13814 
13815   // A key point - if we got here, pre-scheduling was able to find a valid
13816   // scheduling of the sub-graph of the scheduling window which consists
13817   // of all vector bundles and their transitive users.  As such, we do not
13818   // need to reschedule anything *outside of* that subgraph.
13819 
13820   BS->resetSchedule();
13821 
13822   // For the real scheduling we use a more sophisticated ready-list: it is
13823   // sorted by the original instruction location. This lets the final schedule
13824   // be as  close as possible to the original instruction order.
13825   // WARNING: If changing this order causes a correctness issue, that means
13826   // there is some missing dependence edge in the schedule data graph.
13827   struct ScheduleDataCompare {
13828     bool operator()(ScheduleData *SD1, ScheduleData *SD2) const {
13829       return SD2->SchedulingPriority < SD1->SchedulingPriority;
13830     }
13831   };
13832   std::set<ScheduleData *, ScheduleDataCompare> ReadyInsts;
13833 
13834   // Ensure that all dependency data is updated (for nodes in the sub-graph)
13835   // and fill the ready-list with initial instructions.
13836   int Idx = 0;
13837   for (auto *I = BS->ScheduleStart; I != BS->ScheduleEnd;
13838        I = I->getNextNode()) {
13839     BS->doForAllOpcodes(I, [this, &Idx, BS](ScheduleData *SD) {
13840       TreeEntry *SDTE = getTreeEntry(SD->Inst);
13841       (void)SDTE;
13842       assert((isVectorLikeInstWithConstOps(SD->Inst) ||
13843               SD->isPartOfBundle() ==
13844                   (SDTE && !doesNotNeedToSchedule(SDTE->Scalars))) &&
13845              "scheduler and vectorizer bundle mismatch");
13846       SD->FirstInBundle->SchedulingPriority = Idx++;
13847 
13848       if (SD->isSchedulingEntity() && SD->isPartOfBundle())
13849         BS->calculateDependencies(SD, false, this);
13850     });
13851   }
13852   BS->initialFillReadyList(ReadyInsts);
13853 
13854   Instruction *LastScheduledInst = BS->ScheduleEnd;
13855 
13856   // Do the "real" scheduling.
13857   while (!ReadyInsts.empty()) {
13858     ScheduleData *Picked = *ReadyInsts.begin();
13859     ReadyInsts.erase(ReadyInsts.begin());
13860 
13861     // Move the scheduled instruction(s) to their dedicated places, if not
13862     // there yet.
13863     for (ScheduleData *BundleMember = Picked; BundleMember;
13864          BundleMember = BundleMember->NextInBundle) {
13865       Instruction *PickedInst = BundleMember->Inst;
13866       if (PickedInst->getNextNonDebugInstruction() != LastScheduledInst)
13867         PickedInst->moveAfter(LastScheduledInst->getPrevNode());
13868       LastScheduledInst = PickedInst;
13869     }
13870 
13871     BS->schedule(Picked, ReadyInsts);
13872   }
13873 
13874   // Check that we didn't break any of our invariants.
13875 #ifdef EXPENSIVE_CHECKS
13876   BS->verify();
13877 #endif
13878 
13879 #if !defined(NDEBUG) || defined(EXPENSIVE_CHECKS)
13880   // Check that all schedulable entities got scheduled
13881   for (auto *I = BS->ScheduleStart; I != BS->ScheduleEnd; I = I->getNextNode()) {
13882     BS->doForAllOpcodes(I, [&](ScheduleData *SD) {
13883       if (SD->isSchedulingEntity() && SD->hasValidDependencies()) {
13884         assert(SD->IsScheduled && "must be scheduled at this point");
13885       }
13886     });
13887   }
13888 #endif
13889 
13890   // Avoid duplicate scheduling of the block.
13891   BS->ScheduleStart = nullptr;
13892 }
