14365 bool SLPVectorizerPass::runImpl(Function &F, ScalarEvolution *SE_,
14366                                 TargetTransformInfo *TTI_,
14367                                 TargetLibraryInfo *TLI_, AAResults *AA_,
14368                                 LoopInfo *LI_, DominatorTree *DT_,
14369                                 AssumptionCache *AC_, DemandedBits *DB_,
14370                                 OptimizationRemarkEmitter *ORE_) {
14371   if (!RunSLPVectorization)
14372     return false;
14373   SE = SE_;
14374   TTI = TTI_;
14375   TLI = TLI_;
14376   AA = AA_;
14377   LI = LI_;
14378   DT = DT_;
14379   AC = AC_;
14380   DB = DB_;
14381   DL = &F.getParent()->getDataLayout();
14382 
14383   Stores.clear();
14384   GEPs.clear();
14385   bool Changed = false;
14386 
14387   // If the target claims to have no vector registers don't attempt
14388   // vectorization.
14389   if (!TTI->getNumberOfRegisters(TTI->getRegisterClassForType(true))) {
14390     LLVM_DEBUG(
14391         dbgs() << "SLP: Didn't find any vector registers for target, abort.\n");
14392     return false;
14393   }
14394 
14395   // Don't vectorize when the attribute NoImplicitFloat is used.
14396   if (F.hasFnAttribute(Attribute::NoImplicitFloat))
14397     return false;
14398 
14399   LLVM_DEBUG(dbgs() << "SLP: Analyzing blocks in " << F.getName() << ".\n");
14400 
14401   // Use the bottom up slp vectorizer to construct chains that start with
14402   // store instructions.
14403   BoUpSLP R(&F, SE, TTI, TLI, AA, LI, DT, AC, DB, DL, ORE_);
14404 
14405   // A general note: the vectorizer must use BoUpSLP::eraseInstruction() to
14406   // delete instructions.
14407 
14408   // Update DFS numbers now so that we can use them for ordering.
14409   DT->updateDFSNumbers();
14410 
14411   // Scan the blocks in the function in post order.
14412   for (auto *BB : post_order(&F.getEntryBlock())) {
14413     // Start new block - clear the list of reduction roots.
14414     R.clearReductionData();
14415     collectSeedInstructions(BB);
14416 
14417     // Vectorize trees that end at stores.
14418     if (!Stores.empty()) {
14419       LLVM_DEBUG(dbgs() << "SLP: Found stores for " << Stores.size()
14420                         << " underlying objects.\n");
14421       Changed |= vectorizeStoreChains(R);
14422     }
14423 
14424     // Vectorize trees that end at reductions.
14425     Changed |= vectorizeChainsInBlock(BB, R);
14426 
14427     // Vectorize the index computations of getelementptr instructions. This
14428     // is primarily intended to catch gather-like idioms ending at
14429     // non-consecutive loads.
14430     if (!GEPs.empty()) {
14431       LLVM_DEBUG(dbgs() << "SLP: Found GEPs for " << GEPs.size()
14432                         << " underlying objects.\n");
14433       Changed |= vectorizeGEPIndices(BB, R);
14434     }
14435   }
14436 
14437   if (Changed) {
14438     R.optimizeGatherSequence();
14439     LLVM_DEBUG(dbgs() << "SLP: vectorized \"" << F.getName() << "\"\n");
14440   }
14441   return Changed;
14442 }
